import{_ as o,o as e,c as d,a2 as s}from"./chunks/framework.BWuWLRhz.js";const h=JSON.parse('{"title":"36 · 最佳实践：那些「正确的废话」之外，真正能落地的几条","description":"","frontmatter":{"head":[["meta",{"property":"og:site_name","content":"David Studio AI 编程指南"}]]},"headers":[],"relativePath":"codex/36-best-practices.md","filePath":"codex/36-best-practices.md"}'),r={name:"codex/36-best-practices.md"};function n(a,t,l,i,p,c){return e(),d("div",null,[...t[0]||(t[0]=[s(`<h1 id="_36-·-最佳实践-那些「正确的废话」之外-真正能落地的几条" tabindex="-1">36 · 最佳实践：那些「正确的废话」之外，真正能落地的几条 <a class="header-anchor" href="#_36-·-最佳实践-那些「正确的废话」之外-真正能落地的几条" aria-label="Permalink to &quot;36 · 最佳实践：那些「正确的废话」之外，真正能落地的几条&quot;">​</a></h1><blockquote><p>📚 <strong>系列导航</strong>：上一篇 <a href="./35-cheatsheet">35 命令与配置速查表</a> 把命令、配置键、快捷键摊成一张能贴墙上的速查表。这一篇换个层次——不讲「有哪些功能」，讲「这些功能该怎么组合着用，才能让 Codex 真的省你的事」。下一篇 <a href="./37-faq">37 常见问题排查</a> 再讲「出岔子了怎么办」。</p></blockquote><p>说句实话，我刚拿到 Codex 的时候干过一件挺蠢的事：把官方 best-practices 页从头到尾看了一遍，觉得每条都很有道理，然后……合上页面，一条都没改进自己的用法。</p><p>问题不在我——在于绝大多数所谓最佳实践是正确的废话：「提示要写清楚」「记得测试」「小步迭代」——听着都对，但它没告诉你<strong>清楚到什么程度、测什么、步小到多小</strong>。你点头如捣蒜，回去该怎么用还是怎么用。这种万金油式的建议，本质是把责任又踢回给你。</p><p>所以这一篇我不打算复述那些谁都会说的大道理。我把官方那份 best-practices 啃了一遍，挑出<strong>真正改变了我用法、而且我自己验证过的几条</strong>，每条都给你「为什么要这么做 + 具体怎么做 + 不这么做会踩什么坑」。能落地的才留，听着高大上但落不了地的，一概砍掉。</p><p>说句实话，下面这几条里，大半都是我先用错了、吃了亏，才回头补上的。</p><p><strong>看完这一篇，你会拿到：</strong></p><ul><li>一套把 Codex 当「队友」而非「一次性工具」来配置的思路</li><li><code>AGENTS.md</code>（项目说明书）到底该写什么、写多长才有用</li><li>一个「目标 + 上下文 + 约束 + 验收」的提示四件套，照着填就行</li><li>权限该按场景分几档，新手从哪一档起步</li><li>复杂活儿为什么要先让它出计划、再动手</li><li>怎么让 Codex 自己测、自己审，而不是你盯着每一步</li><li>线上任务怎么先拿证据链、脱敏记录、再确认修复</li><li>一张「踩坑 ❌ / 正确做法 ✅」的对照表，直接抄</li></ul><blockquote><p>⚠️ 命令、配置键、默认行为以 Codex <a href="https://developers.openai.com/codex/learn/best-practices" target="_blank" rel="noreferrer">官方文档</a> 为准；模型名、可用范围随版本和套餐变动，一律以你本地 <code>codex --help</code>、<code>/model</code> 面板和 <code>~/.codex/config.toml</code> 的实际为准。</p></blockquote><hr><h2 id="_01-先换个心态-codex-是你要调教的队友-不是一次性工具" tabindex="-1">01 先换个心态：Codex 是你要调教的队友，不是一次性工具 <a class="header-anchor" href="#_01-先换个心态-codex-是你要调教的队友-不是一次性工具" aria-label="Permalink to &quot;01 先换个心态：Codex 是你要调教的队友，不是一次性工具&quot;">​</a></h2><p>先给结论：<strong>用 Codex 这件事，效果好坏一大半取决于你把它当什么。</strong></p><p>很多人（包括早期的我）把它当成一个「问一句答一句」的搜索框：有问题丢过去，拿到答案就走，下次又从零开始。这么用，它永远只能发挥三成功力。</p><p><strong>类比：Codex 像你新招进来的一个能力很强、但完全不了解你们项目的新同事。</strong> 你不会指望他第一天就什么都懂——你得给他一份入职手册（<code>AGENTS.md</code>）、告诉他代码怎么跑怎么测、踩错了纠正他一次让他记住。调教得越久，他越顺手。反过来，你要是每次都换一个不认识你的临时工来干，那永远在重复解释同一件事。</p><p>官方那份文档里有句话我很认同，大意是：<strong>与其把 Codex 当成一次性助手，不如把它当成一个你会持续配置、持续打磨的队友。</strong> 这一篇后面所有的实践，本质都在围绕这一句展开——把临时的、重复的东西，沉淀成持久的配置。</p><p>我自己的转折点是 2026 年初。在那之前我每开一个新会话，都要把「这项目用 pnpm 不用 npm」「测试跑 <code>pnpm test</code>」「提交信息要中文」这几句重新打一遍，一天打七八遍。直到有天我烦了，把这些塞进 <code>AGENTS.md</code>，世界瞬间清净——这才意识到我之前是在用最笨的方式使一个很聪明的工具。</p><blockquote><p>💡 一句话总结：把 Codex 当持续调教的队友，而不是用完即弃的工具，是所有最佳实践的地基。</p></blockquote><hr><h2 id="_02-把-agents-md-写到位-让它自动「带着上下文」干活" tabindex="-1">02 把 <code>AGENTS.md</code> 写到位：让它自动「带着上下文」干活 <a class="header-anchor" href="#_02-把-agents-md-写到位-让它自动「带着上下文」干活" aria-label="Permalink to &quot;02 把 \`AGENTS.md\` 写到位：让它自动「带着上下文」干活&quot;">​</a></h2><p><strong>为什么要这么做。</strong> 上一节那个痛点的解药就是它。<code>AGENTS.md</code> 是放在项目里的一份说明书，Codex 每次进来会<strong>自动读进上下文</strong>，不用你手动 @。一个项目里反复要交代的事，写一次，永久生效。</p><p><strong>类比：<code>AGENTS.md</code> 是给 AI 看的 README。</strong> 普通 README 写给人，告诉人这项目是干嘛的、怎么跑；<code>AGENTS.md</code> 写给 Codex，告诉它你们这儿的规矩、雷区和「干完算数的标准」。</p><p><strong>怎么做。</strong> 官方建议一份好的 <code>AGENTS.md</code> 覆盖这几块，照着列就行：</p><ul><li>项目结构和重要目录在哪</li><li>怎么把项目跑起来</li><li>构建、测试、lint 各用什么命令</li><li>工程约定和提 PR 的要求</li><li>约束和「绝对别做」的红线</li><li>「干完算数」的标准是什么、怎么验证</li></ul><p>最快的起步方式是在 CLI 里敲 <code>/init</code>，它会在当前目录脚手架一份初始 <code>AGENTS.md</code>。但<strong>别拿来就用</strong>——生成的是模板，你得改成你们项目真实的样子。</p><p><code>AGENTS.md</code> 还能分层：放在 <code>~/.codex/</code> 里的是你个人默认；放在项目根目录的是团队共享规范；放在子目录里的是局部规则。<strong>离当前目录越近的越优先生效。</strong></p><p><strong>反例（我真踩过的）。</strong> 我一开始的毛病是反着来：把一大堆「这次别动数据库」「这次只改这个文件」这种<strong>一次性的指令</strong>全写进 <code>AGENTS.md</code>，结果文件越滚越长、还净是过时规则，Codex 读进去反而被带偏。后来才学乖——</p><blockquote><p>一次性的要求写进提示，持久的规矩才写进 <code>AGENTS.md</code>。短而准，胜过长而虚。</p></blockquote><p>官方有个特别实用的小习惯值得抄：<strong>当 Codex 同一个错误犯了第二次，就让它做个复盘、把教训补进 <code>AGENTS.md</code>。</strong> 这样你的说明书是被真实摩擦喂大的，而不是你拍脑袋写的。</p><blockquote><p>💡 一句话总结：把「持久的规矩」沉淀进 <code>AGENTS.md</code>，短、准、真实，比写一长篇空话管用。</p></blockquote><hr><h2 id="_03-提示别靠灵感-目标-上下文-约束-验收-四件套填空" tabindex="-1">03 提示别靠灵感：目标 + 上下文 + 约束 + 验收，四件套填空 <a class="header-anchor" href="#_03-提示别靠灵感-目标-上下文-约束-验收-四件套填空" aria-label="Permalink to &quot;03 提示别靠灵感：目标 + 上下文 + 约束 + 验收，四件套填空&quot;">​</a></h2><p><strong>为什么要这么做。</strong> 上一篇速查表里说过提示的事，这里只补一个能直接抄的结构。Codex 现在很强，你提示写得糙它也能凑合给个结果；但在大项目、高风险的活儿上，提示糊一点，它就得多猜，猜错了你返工。</p><p>官方给的「好提示默认配方」是四件套，我把它当填空题用：</p><table tabindex="0"><thead><tr><th>要素</th><th>它在回答什么</th><th>不填会怎样</th></tr></thead><tbody><tr><td><strong>目标（Goal）</strong></td><td>你到底要改什么、建什么</td><td>它抓不住重点，做了一堆你没要的</td></tr><tr><td><strong>上下文（Context）</strong></td><td>哪些文件、报错、例子相关（可以 @ 提及文件）</td><td>它在错的地方瞎找，绕远路</td></tr><tr><td><strong>约束（Constraints）</strong></td><td>要守什么规范、架构、安全要求</td><td>它按自己的习惯来，风格全乱</td></tr><tr><td><strong>验收（Done when）</strong></td><td>什么条件成立才算干完</td><td>它觉得「能跑」就交差，bug 留给你</td></tr></tbody></table><p><strong>怎么做。</strong> 你不用每句都写得像合同。但凡是稍微复杂、或者你不想返工的活儿，提交前在脑子里（或者就直接打出来）过一遍这四格：我要它干嘛、相关的料在哪、有什么不能碰、怎么算干完了。</p><p><strong>类比：这四件套像给装修队的交底。</strong> 你不会只说一句「把厨房弄好看点」就让人开工——你得说清要什么风格（目标）、户型图水电图在哪（上下文）、承重墙不能动（约束）、验收时灯能亮水能通橱柜不晃（验收）。交底越清，返工越少。</p><p>我自己最常漏的是<strong>验收</strong>这一格。早些时候我让 Codex 改一个表单校验，只说了「加个手机号格式校验」，没说「加完原有的邮箱校验不能失效、相关测试得过」。它麻溜地加了手机号校验，顺手把邮箱那段逻辑挤坏了，我直到上线前跑测试才发现。从那以后，「Done when」这一格我必填。</p><blockquote><p>💡 一句话总结：提示别靠灵感，照「目标 + 上下文 + 约束 + 验收」四格填空，尤其别漏验收。</p></blockquote><hr><h2 id="_04-复杂活儿先出计划-再动手" tabindex="-1">04 复杂活儿先出计划，再动手 <a class="header-anchor" href="#_04-复杂活儿先出计划-再动手" aria-label="Permalink to &quot;04 复杂活儿先出计划，再动手&quot;">​</a></h2><p><strong>为什么要这么做。</strong> 任务一复杂、一模糊，直接让它写代码，它就得一边猜你的意图一边敲键盘，方向歪了你也很晚才发现。<strong>让它先出个计划，等于在动手前给你一次便宜的「纠偏机会」。</strong></p><p><strong>类比：这就像盖房先看图纸。</strong> 没人会让施工队不画图直接砌墙——砌歪了拆起来肝疼。计划就是那张图，几行字的事，比返工一整段代码便宜太多。</p><p><strong>怎么做。</strong> 官方给了几种路子，我按好上手程度排：</p><ul><li><strong>用 Plan 模式（最推荐）</strong>：在 CLI 里用 <code>/plan</code>，或者按 <kbd>Shift</kbd>+<kbd>Tab</kbd> 切换。它会先收集上下文、问你澄清问题、给一份更靠谱的计划，你点头了它再动手。</li><li><strong>让它反过来采访你</strong>：如果你自己都没想清楚，就让它「先别写，先 challenge 我、把这个模糊的想法问成一个具体的方案」。</li><li><strong>用 <code>PLANS.md</code> 模板</strong>：更进阶的玩法，让多步、长跑的任务都按一份执行计划模板走（以官方 execution plans 指南为准）。</li></ul><p><strong>反例。</strong> 官方把「多步复杂任务跳过规划」明确列进了常见错误，我深有体会。去年我让 Codex 帮我把一个模块从回调写法迁到 async/await，图省事没让它出计划，直接「你看着改」。它改是改了，但中途自作主张把我一个全局错误处理的逻辑也「顺便优化」了，整个改动糊成一团，review 时我看着那份 diff 头大，最后干脆 <code>git reset</code> 重来——这次先 <code>/plan</code>，让它列出「改哪些文件、每个文件改什么、哪些绝对不碰」，确认完再放它走，一遍过。</p><blockquote><p>💡 一句话总结：越复杂越模糊的活儿，越要先 <code>/plan</code> 出计划、确认方向，再让它动手。</p></blockquote><hr><h2 id="_05-权限分档-默认从严-按场景逐步放宽" tabindex="-1">05 权限分档：默认从严，按场景逐步放宽 <a class="header-anchor" href="#_05-权限分档-默认从严-按场景逐步放宽" aria-label="Permalink to &quot;05 权限分档：默认从严，按场景逐步放宽&quot;">​</a></h2><p><strong>为什么要这么做。</strong> Codex 自带操作系统级沙箱，有两个关键旋钮：<strong>审批模式（approval mode）</strong> 管它执行命令前要不要先问你，<strong>沙箱模式（sandbox mode）</strong> 管它能不能读写目录、能碰哪些文件。一上来就给满权限，等于把方向盘和油门同时交给一个你还没摸清脾气的新司机。</p><p><strong>类比：这像给新来的实习生配权限。</strong> 第一天你只给他读代码、本地跑测试的权限；处熟了、信得过了，再逐步开放他改文件、连数据库。没人第一天就把生产环境的钥匙塞给新人。</p><p><strong>怎么做。</strong> 官方建议很直接：</p><ul><li>新手就用<strong>默认权限</strong>起步，审批和沙箱都保持收紧。</li><li>等你摸清了某个工作流、确实需要更顺手了，<strong>再针对可信仓库或特定场景</strong>放宽，而不是一把全开。</li></ul><table tabindex="0"><thead><tr><th>场景</th><th>建议档位</th><th>理由</th></tr></thead><tbody><tr><td>刚上手 / 不熟的项目</td><td>默认（动手前问、沙箱收紧）</td><td>看清它要干嘛再放行，安全</td></tr><tr><td>自己的可信仓库、重复跑的活</td><td>适度放宽审批</td><td>减少一直点「同意」的烦躁</td></tr><tr><td>跑不熟的脚本 / 第三方代码</td><td>收到最紧</td><td>防止它执行你没预期的命令</td></tr></tbody></table><p>官方把「还没摸清工作流就给 Codex 完整电脑权限」单列为一条常见错误。我自己的教训不算惨但够长记性：有阵子嫌每次确认烦，把审批放得很开，结果它在一次重构里执行了个我没细看的清理命令，删了几个我以为还要用的临时文件——不是什么大灾难，但够我心里咯噔一下。<strong>省那几秒确认，不值。</strong></p><blockquote><p>💡 一句话总结：权限默认从严，看清楚再放行；只对可信场景逐步放宽，别图省事一把全开。</p></blockquote><hr><h2 id="_06-让它自验证-测、查、审-别只让它「写完」" tabindex="-1">06 让它自验证：测、查、审，别只让它「写完」 <a class="header-anchor" href="#_06-让它自验证-测、查、审-别只让它「写完」" aria-label="Permalink to &quot;06 让它自验证：测、查、审，别只让它「写完」&quot;">​</a></h2><p><strong>为什么要这么做。</strong> 这是我认为含金量最高的一条。<strong>别让 Codex 写完代码就停</strong>——让它顺手把测试写了、把相关检查跑了、把改动 review 一遍，再交给你。这一步做到位，你省下的是一轮轮「它写、你测、报错、再让它修」的来回。</p><p>但有个前提：<strong>它得知道「好」长什么样。</strong> 这份标准从哪来？要么写在提示里，要么写在 <code>AGENTS.md</code> 里（看，又绕回第 02 节了）。</p><p><strong>怎么做。</strong> 官方说的「让它闭环自查」包含这些动作，你可以直接写进要求里：</p><ul><li>给这次改动写或更新测试</li><li>跑对应的测试套件</li><li>跑 lint、格式化、类型检查</li><li>确认最终行为真的对得上你的需求</li><li>把 diff review 一遍，找 bug、找回归、找危险写法</li></ul><p>CLI 里有个 <code>/review</code> 命令特别值这一节：它能按 PR 风格跟基线分支对比着审、审未提交的改动、审某个 commit，或者按你的自定义指令审。如果你们团队有一份 <code>code_review.md</code> 并在 <code>AGENTS.md</code> 里引用了它，Codex review 时就会照着那份标准走——团队多人协作时，这能让审查口径保持一致。</p><p><strong>反例。</strong> 官方把「不让 agent 看到自己的成果」（也就是没告诉它构建、测试命令怎么跑）列为常见错误。我有过一次反面典型：让它改一个数据处理函数，没让它跑测试，它信誓旦旦说「已完成、逻辑正确」，我也信了。结果那段代码在边界输入下直接抛异常——它压根没机会发现，因为我没让它跑。后来我养成习惯：<strong>凡是改逻辑，提示末尾必带一句「改完跑 <code>&lt;测试命令&gt;</code>，全绿了再告诉我」。</strong> 一句话的事，挡掉了一大半返工。</p><blockquote><p>💡 一句话总结：让 Codex 把测、查、审一起干了再交付，前提是用提示或 <code>AGENTS.md</code> 告诉它「好」的标准。</p></blockquote><hr><h2 id="_07-线上任务先拿证据链-再谈修复" tabindex="-1">07 线上任务先拿证据链，再谈修复 <a class="header-anchor" href="#_07-线上任务先拿证据链-再谈修复" aria-label="Permalink to &quot;07 线上任务先拿证据链，再谈修复&quot;">​</a></h2><p><strong>为什么要这么做。</strong> 本地功能开发可以靠测试收口。线上故障还要回答几个硬问题：用户看到的原始症状是什么、你怎么复现、哪条日志对应这次请求、改完以后有没有从同一条用户路径重新验证。</p><p>我现在把这条写进项目规矩里：<strong>线上问题先取证，再判断，再修。</strong> Codex 会顺着线索查代码，但你一上来就说「帮我修一下」，它会把最像原因的地方当原因，把能跑的本地测试当修复完成。线上任务里，这两个判断都不够。</p><p><strong>怎么做。</strong> 先让它别改代码，只做证据收集。提示可以这么写：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>先不要改代码。请按证据链排查这个线上问题：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 复现用户路径，记录请求方式、状态码、关键响应摘要和时间。</span></span>
<span class="line"><span>2. 查对应时间段的应用日志，只摘出相关错误行。</span></span>
<span class="line"><span>3. 找到涉及的配置、路由、任务或数据表，但不要修改生产状态。</span></span>
<span class="line"><span>4. 给出「已验证事实 / 待确认假设 / 下一步验证」三段结论。</span></span>
<span class="line"><span>5. 输出时脱敏，隐藏 token、私有访问链接、邮箱、手机号、订单号和内部地址。</span></span></code></pre></div><p>这段话把 Codex 从「直接修」拉回「先证明」。它最后给你的判断，必须能从证据里追回去：哪个请求失败、日志哪一行报错、哪个配置参与了这个路径、下一步要用什么动作证伪假设。</p><p>我会在 <code>AGENTS.md</code> 里放一段长期规则，专门约束这类任务：</p><div class="language-md vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">md</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 线上问题处理</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 先复现原问题，记录状态码、关键响应摘要、日志时间和验证路径。</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 未经确认，不要改生产数据、权限、可见性、计费、通知或工单状态。</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 输出内容必须脱敏，不要贴 token、用户信息、私有链接、密钥、完整 IP 或订单号。</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 修复后必须用原用户路径复查；本地测试通过不等于线上恢复。</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 如果不能复查，说明缺哪条证据、为什么缺、下一步谁能补。</span></span></code></pre></div><p>这几条像运维规矩，也适合给 Codex。它读到「修复后必须用原用户路径复查」，就不会只跑一个单元测试就宣布结束；它读到「未经确认，不要改生产数据」，遇到会影响用户状态的操作会先停下来问你。</p><p><strong>脱敏要保留可判断的信息。</strong> 你一脱敏就把证据删光，最后只剩「某接口失败」，后面的人没法排查。保留结构，隐藏敏感值：</p><table tabindex="0"><thead><tr><th>原始信息</th><th>脱敏后还能用的写法</th></tr></thead><tbody><tr><td><code>https://example.com/private/path?token=secret_value</code></td><td><code>https://example.com/private/path?token=&lt;token&gt;</code></td></tr><tr><td><code>user@example.com</code></td><td><code>&lt;user-email&gt;</code></td></tr><tr><td><code>order_20260201_123456</code></td><td><code>&lt;order-id&gt;</code></td></tr><tr><td><code>Authorization: Bearer ...</code></td><td><code>Authorization: Bearer &lt;redacted&gt;</code></td></tr><tr><td><code>2026-02-01 14:03:22 status=500</code></td><td>保留原时间和状态码</td></tr></tbody></table><p>时间、状态码、错误类型、路由形状通常可以留；能直接识别用户、账号、密钥、内部资产的值必须藏。这样别人能跟着证据判断，又不会把敏感信息带进 PR、Issue 或公开聊天。</p><p><strong>怎么验收。</strong> 线上任务的验收标准要回到原路径。接口坏了，就重新打同一个接口，记录新状态码和响应摘要；页面坏了，就用浏览器走一遍用户操作；队列或定时任务坏了，就看下一次任务日志和产物。要是环境权限不足，别含糊写「无法验证」，要写清楚：缺生产权限、缺测试账号、缺外部回调，还是缺用户确认。</p><blockquote><p>💡 一句话总结：线上任务别让 Codex 先猜原因，先让它拿证据链；修完以后从原用户路径复查，脱敏时隐藏敏感值但保留状态码、时间和错误形状。</p></blockquote><hr><h2 id="_08-重活拆给子代理-一条线程只干一件事" tabindex="-1">08 重活拆给子代理，一条线程只干一件事 <a class="header-anchor" href="#_08-重活拆给子代理-一条线程只干一件事" aria-label="Permalink to &quot;08 重活拆给子代理，一条线程只干一件事&quot;">​</a></h2><p><strong>为什么要这么做。</strong> 一个会话（session）不只是聊天记录，它是一条会不断累积上下文的工作线程。线程越长、塞的东西越杂，质量越往下掉。所以<strong>怎么管理线程，直接影响结果好坏</strong>。</p><p><strong>类比：这像管理你的工作台。</strong> 一张桌子上同时摊着三个项目的资料，你找东西、做判断都会变慢、变乱；一张桌子只摆一件正在做的事，效率最高。Codex 的线程就是它的工作台。</p><p><strong>怎么做（两条）。</strong></p><p><strong>第一，一条线程只干一件连贯的事。</strong> 官方原话的意思是：只要还是同一个问题，就待在同一条线程里——它保留了完整的推理脉络。只有当工作<strong>真的分叉</strong>了，才用 <code>/fork</code> 另起一条。换言之，按任务拆线程，而不是按项目拆线程——最该避免的反模式正是「一个项目从头到尾就用一条线程」，那会让上下文越堆越肥、结果越来越差。</p><p><strong>第二，把有边界的杂活甩给子代理（subagent）。</strong> 主线程专注核心问题，那些探索代码、写测试、做 triage 之类「能独立完成、有明确产出」的活儿，丢给子代理去跑，别让它们占用主线程的注意力。</p><p>几个管线程的趁手命令（以你本地 <code>codex --help</code> 实际为准）：</p><ul><li><code>/resume</code> 接着一段存档的对话往下聊</li><li><code>/fork</code> 在保留原记录的前提下另起一条新线程</li><li><code>/compact</code> 线程太长时，把早先的上下文压缩成摘要（Codex 也会自动压缩）</li><li><code>/status</code> 看一眼当前会话状态</li></ul><p>我现在的习惯是「一个任务一条线程」，任务做完那条就归档。这个改动看着小，但自从不再用「一个项目一条万能线程」之后，Codex 给我的回答明显没那么容易「串味」了——以前它经常拿三天前另一个需求的上下文来污染当前判断。</p><blockquote><p>💡 一句话总结：一条线程只干一件事，重活、杂活拆给子代理，别让上下文越堆越肥。</p></blockquote><hr><h2 id="_09-上手清单-一张「踩坑-❌-正确做法-✅」对照表" tabindex="-1">09 上手清单：一张「踩坑 ❌ / 正确做法 ✅」对照表 <a class="header-anchor" href="#_09-上手清单-一张「踩坑-❌-正确做法-✅」对照表" aria-label="Permalink to &quot;09 上手清单：一张「踩坑 ❌ / 正确做法 ✅」对照表&quot;">​</a></h2><p>前面八节的精华，官方在文末用一份「常见错误」清单收了尾。我把它揉成一张对照表，你可以照着自查——左边但凡中了一条，就照右边改。</p><table tabindex="0"><thead><tr><th>❌ 我见过的踩坑</th><th>✅ 正确做法</th></tr></thead><tbody><tr><td>把持久规则一股脑塞进提示里</td><td>持久的搬进 <code>AGENTS.md</code> 或 skill，提示只放一次性需求</td></tr><tr><td>没告诉它构建、测试命令怎么跑</td><td>在 <code>AGENTS.md</code> 里写清运行和测试方式，让它能看到自己的成果</td></tr><tr><td>多步复杂任务跳过规划直接写</td><td>复杂活先 <code>/plan</code> 出计划、确认方向再动手</td></tr><tr><td>还没摸清工作流就给满权限</td><td>默认从严，按可信场景逐步放宽</td></tr><tr><td>一个项目从头到尾就一条线程</td><td>一个任务一条线程，分叉了才 <code>/fork</code></td></tr><tr><td>多条线程同时改同一批文件，却不用 git worktree</td><td>用 git worktree 给并行的线程各开一份独立工作区，互不踩脚</td></tr><tr><td>把还不靠谱的活急着做成自动化</td><td>先手动跑稳、再考虑沉淀成 skill 或自动化</td></tr><tr><td>盯着它一步步看，自己干不了别的</td><td>让它并行跑，你腾出手做自己的事</td></tr><tr><td>线上问题没复现就开修</td><td>先记录原始症状、请求状态、日志时间和待验证假设</td></tr><tr><td>本地测试通过就宣布线上恢复</td><td>回到原用户路径复查，记录修复后的状态码、页面行为或任务日志</td></tr><tr><td>把日志、链接、用户信息原样贴进公开 PR</td><td>脱敏敏感值，保留时间、状态码、错误类型和路由形状</td></tr></tbody></table><p><strong>怎么照做。</strong> 这张表别只看一遍。我的建议是：<strong>下次你用 Codex 觉得「不顺、返工多」的时候，回来对一遍左列，大概率能定位到是哪一条没做好。</strong> 这几条踩坑，我没一条是听来的——全是自己撞过南墙才记住的。</p><blockquote><p>💡 一句话总结：照这张对照表自查，左列中招就按右列改，比记任何「最佳实践」口诀都管用。</p></blockquote><hr><h2 id="_10-小结" tabindex="-1">10 小结 <a class="header-anchor" href="#_10-小结" aria-label="Permalink to &quot;10 小结&quot;">​</a></h2><p>这一篇没给你正确的废话，给的是八条我自己验证过、能直接改变用法的实践：</p><ul><li><strong>换心态</strong>：把 Codex 当持续调教的队友，是一切的地基。</li><li><strong>写 <code>AGENTS.md</code></strong>：把持久的规矩沉淀进去，短、准、真实。</li><li><strong>提示四件套</strong>：目标 + 上下文 + 约束 + 验收，照着填，别漏验收。</li><li><strong>先计划后动手</strong>：复杂活先 <code>/plan</code>，便宜的纠偏机会别省。</li><li><strong>权限分档</strong>：默认从严，看清楚再放行。</li><li><strong>让它自验证</strong>：测、查、审一起干，前提是告诉它「好」的标准。</li><li><strong>线上先取证</strong>：复现、日志、状态码、脱敏、原路径复查，一条都别省。</li><li><strong>管好线程</strong>：一条线程一件事，重活甩给子代理。</li></ul><p><strong>你现在应该能</strong>：拿到任意一个 Codex 任务时，下意识过一遍——这活儿要不要先出计划、提示四件套填全没、<code>AGENTS.md</code> 里的规矩够不够、要不要让它自测、该用哪档权限、是不是需要先拿线上证据链。把这套变成肌肉记忆，你跟 Codex 的协作就从「碰运气」变成了「有章法」。</p><hr><p>下一篇〔<a href="./37-faq">37 常见问题排查</a> 〕，咱们聊点更接地气的：再守规矩，Codex 也总有给你出岔子的时候——命令报错、改坏了、连不上、行为反常。出问题不可怕，可怕的是不知道从哪儿查起。留个小思考：这一篇讲的「先 <code>/plan</code>、勤自测、小步走」，其实大半也是在<strong>预防</strong>问题；那万一问题真发生了，你第一反应该去看哪儿？下一篇给你一套排查的先后顺序。</p>`,103)])])}const k=o(r,[["render",n]]);export{h as __pageData,k as default};
